#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

// Define the integrand function: f(x) = x^2
// Change this function to integrate different functions
double f(double x) {
 return x * x;
}

// Method 1: BEST - Using reduction clause (recommended)
double trapezoidal_reduction(double a, double b, int n, int thread_count) {
 double h = (b - a) / n;
 double integral = (f(a) + f(b)) / 2.0;

 // The reduction clause:
 // - Creates a private copy of 'integral' for each thread, initialized to 0
 // - Each thread adds to its private copy
 // - Private copies are combined at the end using + operation
 #pragma omp parallel for num_threads(thread_count) \
 reduction(+: integral)
 for (int i = 1; i < n; i++) {
 double x_i = a + i * h;
 integral += f(x_i);
 }

 integral *= h;
 return integral;
}

// Method 2: WORST - Using critical section per iteration
double trapezoidal_critical(double a, double b, int n, int thread_count) {
 double h = (b - a) / n;
 double integral = (f(a) + f(b)) / 2.0;

 #pragma omp parallel for num_threads(thread_count)
 for (int i = 1; i < n; i++) {
 double x_i = a + i * h;

 // Critical section serializes access - major performance bottleneck!
 #pragma omp critical
 {
 integral += f(x_i);
 }
 }

 integral *= h;
 return integral;
}

// Method 3: GOOD - Manual decomposition with local sum
double trapezoidal_manual(double a, double b, int n, int thread_count) {
 double h = (b - a) / n;
 double global_integral = (f(a) + f(b)) / 2.0;

 #pragma omp parallel num_threads(thread_count)
 {
 int my_rank = omp_get_thread_num();
 int num_threads = omp_get_num_threads();
 double local_sum = 0.0;

 // Each thread handles non-overlapping iterations (stride = num_threads)
 // This is like block decomposition in parallel computing
 for (int i = my_rank + 1; i < n; i += num_threads) {
 double x_i = a + i * h;
 local_sum += f(x_i);
 }

 // Only ONE critical section per thread (reduced contention)
 #pragma omp critical
 {
 global_integral += local_sum;
 }
 }

 global_integral *= h;
 return global_integral;
}

// Sequential version for comparison
double trapezoidal_sequential(double a, double b, int n) {
 double h = (b - a) / n;
 double integral = (f(a) + f(b)) / 2.0;

 for (int i = 1; i < n; i++) {
 double x_i = a + i * h;
 integral += f(x_i);
 }

 integral *= h;
 return integral;
}

int main(int argc, char* argv[]) {
 double a = 0.0; // Lower bound
 double b = 1.0; // Upper bound
 int n = 1000000; // Number of subintervals
 int thread_count = 4;

 // Allow command-line arguments
 if (argc >= 2) n = atoi(argv[1]);
 if (argc >= 3) thread_count = atoi(argv[2]);

 double exact = 1.0 / 3.0; // Exact integral of x^2 from 0 to 1

 printf("================================================\n");
 printf("Trapezoidal Rule - OpenMP Parallel Implementation\n");
 printf("Integrating f(x) = x^2 from %.1f to %.1f\n", a, b);
 printf("Number of subintervals (n): %d\n", n);
 printf("Number of threads: %d\n", thread_count);
 printf("Exact value: %.15f\n", exact);
 printf("================================================\n\n");

 // Sequential timing
 double start = omp_get_wtime();
 double result_seq = trapezoidal_sequential(a, b, n);
 double time_seq = omp_get_wtime() - start;
 printf("Sequential: %.15f Error: %.2e Time: %.6fs\n",
 result_seq, fabs(result_seq - exact), time_seq);

 // Reduction method timing
 start = omp_get_wtime();
 double result_red = trapezoidal_reduction(a, b, n, thread_count);
 double time_red = omp_get_wtime() - start;
 printf("Reduction: %.15f Error: %.2e Time: %.6fs Speedup: %.2fx\n",
 result_red, fabs(result_red - exact), time_red, time_seq/time_red);

 // Critical section method timing
 start = omp_get_wtime();
 double result_crit = trapezoidal_critical(a, b, n, thread_count);
 double time_crit = omp_get_wtime() - start;
 printf("Critical: %.15f Error: %.2e Time: %.6fs Speedup: %.2fx\n",
 result_crit, fabs(result_crit - exact), time_crit, time_seq/time_crit);

 // Manual decomposition method timing
 start = omp_get_wtime();
 double result_man = trapezoidal_manual(a, b, n, thread_count);
 double time_man = omp_get_wtime() - start;
 printf("Manual: %.15f Error: %.2e Time: %.6fs Speedup: %.2fx\n",
 result_man, fabs(result_man - exact), time_man, time_seq/time_man);

 printf("\n================================================\n");
 printf("Performance Comparison:\n");
 printf("Reduction is %.2fx faster than Critical\n", time_crit/time_red);
 printf("Reduction is %.2fx faster than Manual\n", time_man/time_red);
 printf("================================================\n");

 return 0;
}

/*
 * COMPILATION:
 * gcc -fopenmp -O2 -o trapezoid trapezoid.c -lm
 * 
 * RUNNING:
 * ./trapezoid [n] [threads]
 * Example: ./trapezoid 1000000 4
 * 
 * ENVIRONMENT VARIABLE:
 * export OMP_NUM_THREADS=4
 */

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicDouble;

public class TrapezoidalRule {

 // Integrand function: f(x) = x^2
 private static double f(double x) {
 return x * x;
 }

 // Method 1: Sequential trapezoidal rule
 public static double sequential(double a, double b, int n) {
 double h = (b - a) / n;
 double integral = (f(a) + f(b)) / 2.0;

 for (int i = 1; i < n; i++) {
 double x_i = a + i * h;
 integral += f(x_i);
 }

 return integral * h;
 }

 // Method 2: Parallel using ExecutorService with reduction pattern
 // Each thread computes a partial sum, then all partial sums are combined
 public static double parallelReduction(double a, double b, int n, int numThreads) 
 throws Exception {
 double h = (b - a) / n;
 ExecutorService executor = Executors.newFixedThreadPool(numThreads);

 // Create tasks for parallel execution
 int chunkSize = (n - 1) / numThreads;
 Future<Double>[] futures = new Future[numThreads];

 for (int t = 0; t < numThreads; t++) {
 final int threadId = t;
 final int startIdx = t * chunkSize + 1;
 final int endIdx = (t == numThreads - 1) ? n : (t + 1) * chunkSize + 1;

 futures[t] = executor.submit(() -> {
 double localSum = 0.0;
 for (int i = startIdx; i < endIdx; i++) {
 double x_i = a + i * h;
 localSum += f(x_i);
 }
 return localSum;
 });
 }

 // Collect partial sums (reduction operation)
 double integral = (f(a) + f(b)) / 2.0;
 for (Future<Double> future : futures) {
 integral += future.get();
 }

 executor.shutdown();
 return integral * h;
 }

 // Method 3: Parallel using AtomicDouble (like critical section)
 public static double parallelAtomic(double a, double b, int n, int numThreads) 
 throws Exception {
 double h = (b - a) / n;
 ExecutorService executor = Executors.newFixedThreadPool(numThreads);
 AtomicDouble integral = new AtomicDouble((f(a) + f(b)) / 2.0);

 int chunkSize = (n - 1) / numThreads;

 for (int t = 0; t < numThreads; t++) {
 final int startIdx = t * chunkSize + 1;
 final int endIdx = (t == numThreads - 1) ? n : (t + 1) * chunkSize + 1;

 executor.submit(() -> {
 for (int i = startIdx; i < endIdx; i++) {
 double x_i = a + i * h;
 // Atomic update - similar to critical section
 integral.addAndGet(f(x_i));
 }
 });
 }

 executor.shutdown();
 while (!executor.isTerminated()) {
 Thread.sleep(10);
 }

 return integral.get() * h;
 }

 public static void main(String[] args) {
 double a = 0.0; // Lower bound
 double b = 1.0; // Upper bound
 int n = 1000000; // Number of subintervals
 int numThreads = 4;

 double exact = 1.0 / 3.0;

 System.out.println("================================================");
 System.out.println("Trapezoidal Rule - Java Parallel Implementation");
 System.out.println("Integrating f(x) = x^2 from " + a + " to " + b);
 System.out.println("Number of subintervals (n): " + n);
 System.out.println("Number of threads: " + numThreads);
 System.out.println("Exact value: " + exact);
 System.out.println("================================================\n");

 // Sequential
 long startTime = System.nanoTime();
 double resultSeq = sequential(a, b, n);
 long timeSeq = System.nanoTime() - startTime;
 System.out.printf("Sequential: %.15f Error: %.2e Time: %.6fs%n",
 resultSeq, Math.abs(resultSeq - exact), timeSeq / 1e9);

 // Parallel with reduction pattern
 try {
 startTime = System.nanoTime();
 double resultRed = parallelReduction(a, b, n, numThreads);
 long timeRed = System.nanoTime() - startTime;
 System.out.printf("Reduction: %.15f Error: %.2e Time: %.6fs Speedup: %.2fx%n",
 resultRed, Math.abs(resultRed - exact), timeRed / 1e9, 
 (double) timeSeq / timeRed);

 // Parallel with Atomic (critical-like)
 startTime = System.nanoTime();
 double resultAtom = parallelAtomic(a, b, n, numThreads);
 long timeAtom = System.nanoTime() - startTime;
 System.out.printf("Atomic: %.15f Error: %.2e Time: %.6fs Speedup: %.2fx%n",
 resultAtom, Math.abs(resultAtom - exact), timeAtom / 1e9,
 (double) timeSeq / timeAtom);

 } catch (Exception e) {
 e.printStackTrace();
 }

 System.out.println("\n================================================");
 System.out.println("Note: Java uses thread pools instead of OpenMP");
 System.out.println("Reduction pattern (Future.get) is more efficient");
 System.out.println("================================================");
 }
}

/*
 * COMPILATION:
 * javac TrapezoidalRule.java
 * 
 * EXECUTION:
 * java TrapezoidalRule
 * 
 * KEY CONCEPTS DEMONSTRATED:
 * - ExecutorService: Similar to OpenMP thread pool
 * - Future: Represents pending result (like thread-private variables)
 * - AtomicDouble: Thread-safe counter (like critical section)
 * - Reduction pattern: Collect partial results and combine
 */
